import json
import random
import datetime
import os

import modal

# ---------------------------------------------------------------------------
# Shared infrastructure
# ---------------------------------------------------------------------------

app = modal.App("etl-pipeline")

# Network File System for raw and processed data
nfs = modal.NetworkFileSystem.from_name("etl-nfs", create_if_missing=True)

# Modal Dict for pipeline metadata
pipeline_metadata = modal.Dict.from_name("etl-pipeline-metadata", create_if_missing=True)

# Base image with FastAPI/uvicorn available
image = modal.Image.debian_slim().pip_install("fastapi", "uvicorn")

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

CATEGORIES = ["alpha", "beta", "gamma", "delta", "epsilon"]
NFS_MOUNT = "/data"


# ---------------------------------------------------------------------------
# Helper – generate a batch of synthetic records
# ---------------------------------------------------------------------------

def _generate_records(n: int = 50) -> list[dict]:
    now = datetime.datetime.utcnow().isoformat()
    return [
        {
            "category": random.choice(CATEGORIES),
            "value": round(random.uniform(1.0, 1000.0), 2),
            "timestamp": now,
        }
        for _ in range(n)
    ]


# ---------------------------------------------------------------------------
# Processing function (fault-tolerant)
# ---------------------------------------------------------------------------

@app.function(
    image=image,
    network_file_systems={NFS_MOUNT: nfs},
    retries=3,
    timeout=120,
)
def process_batch(raw_filename: str):
    """Read raw JSON from NFS, aggregate by category, write processed JSON."""
    raw_path = os.path.join(NFS_MOUNT, raw_filename)

    with open(raw_path, "r") as f:
        records = json.load(f)

    # Aggregate: count and sum per category
    aggregation: dict[str, dict] = {}
    for rec in records:
        cat = rec["category"]
        if cat not in aggregation:
            aggregation[cat] = {"count": 0, "sum": 0.0}
        aggregation[cat]["count"] += 1
        aggregation[cat]["sum"] = round(aggregation[cat]["sum"] + rec["value"], 2)

    # Derive timestamp tag from raw filename  e.g. raw_20260326T075511.json
    timestamp_tag = raw_filename.removeprefix("raw_").removesuffix(".json")
    processed_filename = f"processed_{timestamp_tag}.json"
    processed_path = os.path.join(NFS_MOUNT, processed_filename)

    output = {
        "source_file": raw_filename,
        "processed_at": datetime.datetime.utcnow().isoformat(),
        "aggregation": aggregation,
    }

    with open(processed_path, "w") as f:
        json.dump(output, f, indent=2)

    print(f"[process_batch] wrote {processed_path}")
    return processed_filename


# ---------------------------------------------------------------------------
# Ingestion function (scheduled every 5 minutes)
# ---------------------------------------------------------------------------

@app.function(
    image=image,
    network_file_systems={NFS_MOUNT: nfs},
    schedule=modal.Period(minutes=5),
)
def ingest_data():
    """Generate synthetic records, persist to NFS, kick off processing."""
    timestamp_tag = datetime.datetime.utcnow().strftime("%Y%m%dT%H%M%S")
    raw_filename = f"raw_{timestamp_tag}.json"
    raw_path = os.path.join(NFS_MOUNT, raw_filename)

    records = _generate_records(50)
    with open(raw_path, "w") as f:
        json.dump(records, f, indent=2)

    print(f"[ingest_data] wrote {raw_path} ({len(records)} records)")

    # Update metadata – run_count and last_run_timestamp
    try:
        run_count = pipeline_metadata.get("run_count", 0) + 1
    except Exception:
        run_count = 1

    try:
        error_count = pipeline_metadata.get("error_count", 0)
    except Exception:
        error_count = 0

    pipeline_metadata["run_count"] = run_count
    pipeline_metadata["last_run_timestamp"] = datetime.datetime.utcnow().isoformat()
    pipeline_metadata["error_count"] = error_count

    # Kick off processing
    try:
        processed_filename = process_batch.remote(raw_filename)
        print(f"[ingest_data] processing complete → {processed_filename}")
    except Exception as exc:
        # Increment error counter but don't swallow the exception entirely
        try:
            pipeline_metadata["error_count"] = pipeline_metadata.get("error_count", 0) + 1
        except Exception:
            pass
        print(f"[ingest_data] processing failed: {exc}")
        raise

    return raw_filename


# ---------------------------------------------------------------------------
# FastAPI status endpoint
# ---------------------------------------------------------------------------

@app.function(
    image=image,
    network_file_systems={NFS_MOUNT: nfs},
)
@modal.asgi_app()
def web_app():
    from fastapi import FastAPI
    from fastapi.responses import JSONResponse

    api = FastAPI(title="ETL Pipeline Status")

    @api.get("/status")
    def status():
        # Find the most recent processed file
        try:
            all_files = os.listdir(NFS_MOUNT)
        except Exception as exc:
            return JSONResponse(
                status_code=500,
                content={"error": f"Cannot list NFS: {exc}"},
            )

        processed_files = sorted(
            [f for f in all_files if f.startswith("processed_") and f.endswith(".json")]
        )

        if not processed_files:
            return JSONResponse(
                content={"status": "pipeline has not run yet", "data": None}
            )

        latest = processed_files[-1]
        latest_path = os.path.join(NFS_MOUNT, latest)
        try:
            with open(latest_path, "r") as f:
                data = json.load(f)
        except Exception as exc:
            return JSONResponse(
                status_code=500,
                content={"error": f"Cannot read {latest}: {exc}"},
            )

        # Fetch metadata from Modal Dict
        meta: dict = {}
        for key in ("run_count", "last_run_timestamp", "error_count"):
            try:
                meta[key] = pipeline_metadata.get(key, None)
            except Exception:
                meta[key] = None

        return JSONResponse(
            content={
                "status": "ok",
                "latest_processed_file": latest,
                "pipeline_metadata": meta,
                "data": data,
            }
        )

    return api


# ---------------------------------------------------------------------------
# Local entrypoint – manual trigger
# ---------------------------------------------------------------------------

@app.local_entrypoint()
def main():
    """Manually trigger a full ingest-and-process cycle."""
    print("[main] Starting manual ETL run …")
    raw_filename = ingest_data.remote()
    print(f"[main] Pipeline complete. Raw file: {raw_filename}")

    # Print current metadata
    for key in ("run_count", "last_run_timestamp", "error_count"):
        try:
            val = pipeline_metadata.get(key, "N/A")
        except Exception:
            val = "N/A"
        print(f"  {key}: {val}")
